SELECT SUM(CASE WHEN Country = 'CZE' THEN 1 ELSE 0 END) - SUM(CASE WHEN Country = 'SVK' THEN 1 ELSE 0 END) AS Difference
FROM gasstations
WHERE Segment = 'Discount';

1526:
SELECT (consumption_2012 - consumption_2013) / consumption_2012 AS consumption_decrease_rate FROM (
  SELECT SUM(CASE WHEN strftime('%Y', Date) = '2012' THEN Consumption ELSE 0 END) AS consumption_2012,
         SUM(CASE WHEN strftime('%Y', Date) = '2013' THEN Consumption ELSE 0 END) AS consumption_2013
  FROM yearmonth
  WHERE CustomerID IN (
    SELECT CustomerID FROM transactions_1k WHERE Date = '2012-08-25' AND Amount = 634.8
  )
);

487:
SELECT CAST(SUM(CASE WHEN cardKingdomFoilId IS NOT NULL AND cardKingdomId IS NOT NULL THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) AS percentage_incredibly_powerful_cards
FROM cards
WHERE setCode = 'Coldsnap';

228:
SELECT ROUND(COUNT(CASE WHEN element = 'h' THEN 1 ELSE NULL END) * 100.0 / COUNT(*), 4) AS percent
FROM atom
WHERE molecule_id = 'TR206';

