SELECT (MAX(AVG_A11) - MIN(AVG_A11)) AS gap FROM (
    SELECT AVG(d.A11) AS AVG_A11, c.district_id FROM client c JOIN district d ON c.district_id = d.district_id GROUP BY c.district_id
) AS subquery

